const fs = require('fs');
const config = $('Config').first().json;
const componentSetsPayload = $('Get Figma Component Sets').first().json;
const componentsPayload = $('Get Figma Components').first().json;
const documentPayload = $('Get Figma File Fallback').first().json;
const tokens = JSON.parse(fs.readFileSync(config.tokens_path, 'utf8'));

function normalizeName(value) {
  return String(value || '')
    .split('/')
    .pop()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '');
}

function toList(payload, key) {
  return payload?.meta?.[key] || payload?.[key] || [];
}

const tokenNames = new Set(Object.keys(tokens.component || {}).map(normalizeName).filter(Boolean));

function discoverFromComponentEndpoints() {
  const seen = new Set();
  const discovered = [];
  function add(item, kind) {
    const name = item?.name || '';
    const nodeId = item?.node_id || item?.nodeId;
    if (!nodeId || !tokenNames.has(normalizeName(name)) || seen.has(nodeId)) return;
    seen.add(nodeId);
    discovered.push({ nodeId, name, kind });
  }
  for (const item of toList(componentSetsPayload, 'component_sets')) add(item, 'component_set');
  for (const item of toList(componentsPayload, 'components')) {
    if (item.component_set_id || item.componentSetId) continue;
    add(item, 'component');
  }
  return discovered;
}

function discoverFromDocument() {
  const seen = new Set();
  const discovered = [];
  function visit(node, trail = []) {
    if (!node || typeof node !== 'object') return;
    const nextTrail = node.name ? [...trail, node.name] : trail;
    if ((node.type === 'COMPONENT_SET' || node.type === 'COMPONENT') && tokenNames.has(normalizeName(node.name))) {
      if (node.id && !seen.has(node.id)) {
        seen.add(node.id);
        discovered.push({ nodeId: node.id, name: node.name, kind: node.type.toLowerCase(), path: nextTrail.join(' / ') });
      }
    }
    for (const child of node.children || []) visit(child, nextTrail);
  }
  visit(documentPayload?.document);
  return discovered;
}

let discoverySource = 'component_sets + components';
let discovered = discoverFromComponentEndpoints();
if (!discovered.length) {
  discovered = discoverFromDocument();
  discoverySource = 'full file traversal';
}

discovered.sort((a, b) => a.name.localeCompare(b.name));
if (!discovered.length) {
  throw new Error('Aucun composant Figma ne correspond aux entrees tokens.json > component.*');
}

return [{ json: { ...config, discovered, discovery_source: discoverySource, component_ids: discovered.map((item) => item.nodeId).join(',') } }];

const fs = require('fs');
const config = $('Discover DS Components').first().json;
const response = $input.first().json;
const nodes = response.nodes || {};

function rgbaToCSS(color) {
  if (!color) return null;
  const r = Math.round((color.r || 0) * 255);
  const g = Math.round((color.g || 0) * 255);
  const b = Math.round((color.b || 0) * 255);
  const a = color.a !== undefined ? color.a : 1;
  return a < 1 ? `rgba(${r}, ${g}, ${b}, ${Number(a.toFixed(3))})` : `#${r.toString(16).padStart(2,'0')}${g.toString(16).padStart(2,'0')}${b.toString(16).padStart(2,'0')}`;
}

function extractFills(fills) {
  if (!Array.isArray(fills)) return [];
  return fills.filter(f => f.visible !== false).map(f => ({ type: f.type, color: f.type === 'SOLID' ? rgbaToCSS(f.color) : null, opacity: f.opacity }));
}

function extractEffects(effects) {
  if (!Array.isArray(effects)) return [];
  return effects.filter(e => e.visible !== false).map(e => {
    if (e.type === 'DROP_SHADOW' || e.type === 'INNER_SHADOW') {
      const inset = e.type === 'INNER_SHADOW' ? 'inset ' : '';
      return { type: e.type, css: `${inset}${e.offset?.x || 0}px ${e.offset?.y || 0}px ${e.radius || 0}px ${e.spread || 0}px ${rgbaToCSS(e.color)}` };
    }
    return { type: e.type };
  });
}

function extractTextStyle(node) {
  if (node.type !== 'TEXT' || !node.style) return null;
  const s = node.style;
  return {
    fontFamily: s.fontFamily || null,
    fontSize: s.fontSize ? `${s.fontSize}px` : null,
    fontWeight: s.fontWeight || null,
    lineHeight: s.lineHeightPx ? `${Math.round(s.lineHeightPx)}px` : null,
    letterSpacing: s.letterSpacing ? `${s.letterSpacing}px` : null,
    textAlign: s.textAlignHorizontal?.toLowerCase() || null
  };
}

function extractAutoLayout(node) {
  if (!node.layoutMode || node.layoutMode === 'NONE') return null;
  return {
    direction: node.layoutMode === 'HORIZONTAL' ? 'row' : 'column',
    gap: node.itemSpacing != null ? `${node.itemSpacing}px` : null,
    paddingTop: node.paddingTop != null ? `${node.paddingTop}px` : null,
    paddingRight: node.paddingRight != null ? `${node.paddingRight}px` : null,
    paddingBottom: node.paddingBottom != null ? `${node.paddingBottom}px` : null,
    paddingLeft: node.paddingLeft != null ? `${node.paddingLeft}px` : null,
    alignItems: node.counterAxisAlignItems === 'CENTER' ? 'center' : (node.counterAxisAlignItems === 'MAX' ? 'flex-end' : 'flex-start'),
    justifyContent: node.primaryAxisAlignItems === 'CENTER' ? 'center' : (node.primaryAxisAlignItems === 'SPACE_BETWEEN' ? 'space-between' : 'flex-start')
  };
}

function extractDesignSpec(node) {
  const spec = {
    name: node.name, type: node.type,
    width: node.absoluteBoundingBox?.width ? `${Math.round(node.absoluteBoundingBox.width)}px` : null,
    height: node.absoluteBoundingBox?.height ? `${Math.round(node.absoluteBoundingBox.height)}px` : null,
    cornerRadius: node.cornerRadius != null ? `${node.cornerRadius}px` : null,
    cornerRadii: node.rectangleCornerRadii || null,
    fills: extractFills(node.fills),
    strokes: Array.isArray(node.strokes) ? node.strokes.filter(s => s.visible !== false).map(s => ({ color: rgbaToCSS(s.color), weight: node.strokeWeight ? `${node.strokeWeight}px` : null, align: node.strokeAlign })) : [],
    effects: extractEffects(node.effects),
    autoLayout: extractAutoLayout(node),
    textStyle: extractTextStyle(node),
    opacity: node.opacity != null && node.opacity < 1 ? node.opacity : null,
    clipsContent: node.clipsContent ?? false
  };
  if (Array.isArray(node.children) && node.children.length > 0) spec.children = node.children.map(child => extractDesignSpec(child));
  return spec;
}

const designSpecs = {};
for (const nodeData of Object.values(nodes)) {
  const doc = nodeData?.document || nodeData;
  if (doc?.name) designSpecs[doc.name] = extractDesignSpec(doc);
}

const cache = {
  _meta: {
    cached_at: new Date().toISOString(),
    figma_file_key: config.figma_file_key,
    source: `Figma REST API auto-discovery: ${config.discovery_source} + nodes`,
    node_ids: config.component_ids,
    discovered_components: config.discovered
  },
  figma_design_specs: designSpecs,
  specs_count: Object.keys(designSpecs).length
};

fs.writeFileSync(config.cache_path, JSON.stringify(cache, null, 2), 'utf8');
return [{ json: { message: 'Cache Figma auto mis a jour', cached_at: cache._meta.cached_at, components: Object.keys(designSpecs), specs_count: cache.specs_count, cache_path: config.cache_path } }];
